INSERT INTO fabric_patterns (fabric_id,pattern_name,courses_per_repeat,wales_per_repeat,pattern_type,pattern_cylinder,pattern_dial,cam_arrangement,needle_butt_pattern,needle_description) VALUES (3,'default',4,4,'single','[["K","T","K","T"],["T","K","T","K"],["K","T","K","T"],["T","K","T","K"]]',NULL,'[{"feed":1,"cylinder":"K/T alternate","note":"A=K, B=T"},{"feed":2,"cylinder":"T/K alternate","note":"A=T, B=K"},{"feed":3,"cylinder":"K/T alternate","note":"same as feed 1"},{"feed":4,"cylinder":"T/K alternate","note":"same as feed 2"}]','ABAB','Alternating long-short butt');
INSERT INTO fabric_patterns (fabric_id,pattern_name,courses_per_repeat,wales_per_repeat,pattern_type,pattern_cylinder,pattern_dial,cam_arrangement,needle_butt_pattern,needle_description) VALUES (4,'default',2,2,'single','[["K","T"],["T","K"]]',NULL,'[{"feed":1,"cylinder":"K/T alternate","note":"Odd needles knit, even tuck"},{"feed":2,"cylinder":"T/K alternate","note":"Odd needles tuck, even knit"}]','ABAB','Long (A) and short (B) butt alternating. A-needles follow cam track 1, B follow cam track 2.');
INSERT INTO fabric_patterns (fabric_id,pattern_name,courses_per_repeat,wales_per_repeat,pattern_type,pattern_cylinder,pattern_dial,cam_arrangement,needle_butt_pattern,needle_description) VALUES (5,'default',4,2,'single','[["K","T"],["K","T"],["T","K"],["T","K"]]',NULL,'[{"feed":1,"cylinder":"K/T","note":"A=K, B=T"},{"feed":2,"cylinder":"K/T","note":"Same as feed 1 (double tuck)"},{"feed":3,"cylinder":"T/K","note":"A=T, B=K"},{"feed":4,"cylinder":"T/K","note":"Same as feed 3 (double tuck)"}]','ABAB','Long-short butt alternating');
INSERT INTO fabric_patterns (fabric_id,pattern_name,courses_per_repeat,wales_per_repeat,pattern_type,pattern_cylinder,pattern_dial,cam_arrangement,needle_butt_pattern,needle_description) VALUES (6,'default',2,1,'single','[["K"],["K"]]',NULL,'[{"feed":1,"cylinder":"K","yarn":"ground","note":"Ground yarn knits all needles"},{"feed":2,"cylinder":"K+T alternate","yarn":"tie","note":"Tie yarn tucks every 2nd needle (holds inlay)"},{"feed":3,"cylinder":"inlay","yarn":"pile","note":"Pile yarn floats over sinkers — forms loops on back"}]','AAAA','All needles engaged. Sinker control creates back loops for pile.');
INSERT INTO fabric_patterns (fabric_id,pattern_name,courses_per_repeat,wales_per_repeat,pattern_type,pattern_cylinder,pattern_dial,cam_arrangement,needle_butt_pattern,needle_description) VALUES (7,'default',1,1,'single','[["K"],["K"]]',NULL,'[{"feed":1,"cylinder":"K","yarn":"ground"},{"feed":2,"cylinder":"K+T","yarn":"binder"},{"feed":3,"cylinder":"inlay","yarn":"pile"}]','AAAA','All needles active');
INSERT INTO fabric_patterns (fabric_id,pattern_name,courses_per_repeat,wales_per_repeat,pattern_type,pattern_cylinder,pattern_dial,cam_arrangement,needle_butt_pattern,needle_description) VALUES (8,'default',2,1,'single','[["K"],["K"]]',NULL,'[{"feed":"A","cylinder":"K","yarn":"ground","note":"Ground yarn, short sinker — base structure"},{"feed":"B","cylinder":"K","yarn":"pile","note":"Pile yarn, long sinker advance — forms loops on face or back"}]','AAAA','All needles engaged. Loop height controlled by long/short sinker ring alternation, NOT needle selection.');
INSERT INTO fabric_patterns (fabric_id,pattern_name,courses_per_repeat,wales_per_repeat,pattern_type,pattern_cylinder,pattern_dial,cam_arrangement,needle_butt_pattern,needle_description) VALUES (9,'default',4,4,'single','[["K","K","K","K"],["K","M","K","K"],["K","K","K","K"],["K","K","K","M"]]',NULL,'[{"feed":1,"cylinder":"K","note":"All knit"},{"feed":2,"cylinder":"K/transfer","note":"Transfer needles create hole, adjacent needle double-loop"},{"feed":3,"cylinder":"K","note":"All knit"},{"feed":4,"cylinder":"K/transfer","note":"Transfer at offset position for diamond/chevron pattern"}]','AAAA','All needles; selected needles have transfer/pressing mechanism engaged per course');
INSERT INTO fabric_patterns (fabric_id,pattern_name,courses_per_repeat,wales_per_repeat,pattern_type,pattern_cylinder,pattern_dial,cam_arrangement,needle_butt_pattern,needle_description) VALUES (10,'default',1,1,'single','[["K"]]',NULL,'[{"feed":1,"cylinder":"K","note":"Two yarns fed simultaneously through plating attachment"}]','AAAA','All needles, standard arrangement. Plating attachment positions two yarns so yarn-1 always face, yarn-2 always back.');
INSERT INTO fabric_patterns (fabric_id,pattern_name,courses_per_repeat,wales_per_repeat,pattern_type,pattern_cylinder,pattern_dial,cam_arrangement,needle_butt_pattern,needle_description) VALUES (11,'default',1,1,'single','[["K"]]',NULL,'[{"feed":1,"yarn":"color_A","cylinder":"selective K/M","note":"Electronic selection: color A needles knit, others miss"},{"feed":2,"yarn":"color_B","cylinder":"selective K/M","note":"Electronic selection: color B needles knit, others miss"}]','electronic','Electronic jacquard is design-dependent; this row seeds a minimal placeholder repeat.');
INSERT INTO fabric_patterns (fabric_id,pattern_name,courses_per_repeat,wales_per_repeat,pattern_type,pattern_cylinder,pattern_dial,cam_arrangement,needle_butt_pattern,needle_description) VALUES (12,'default',1,2,'double','[["K"]]','[["K"]]','[{"feed":1,"cylinder":"K","dial":"K","note":"Alternating cylinder and dial needles all knit"}]','C_D_C_D','Alternating cylinder (C) and dial (D) needles. Gating: 90° offset so C and D needles interleave.');
INSERT INTO fabric_patterns (fabric_id,pattern_name,courses_per_repeat,wales_per_repeat,pattern_type,pattern_cylinder,pattern_dial,cam_arrangement,needle_butt_pattern,needle_description) VALUES (13,'default',1,4,'double','[["K","K","M","M"]]','[["M","M","K","K"]]','[{"feed":1,"cylinder":"K on 2 needles","dial":"K on 2 needles","note":"Groups of 2 cylinder then 2 dial needles active"}]','CC_DD_CC_DD','2 cylinder needles active, 2 dial, 2 cylinder... Remaining needles disengaged or removed.');
INSERT INTO fabric_patterns (fabric_id,pattern_name,courses_per_repeat,wales_per_repeat,pattern_type,pattern_cylinder,pattern_dial,cam_arrangement,needle_butt_pattern,needle_description) VALUES (14,'default',1,2,'double','[["K"]]','[["K"]]','[{"feed":1,"cylinder":"K","dial":"K","note":"Alternating cylinder and dial needles knit main spun cotton yarn plated with elastane (Lycra)"}]','C_D_C_D','Alternating cylinder (C) and dial (D) needles. Dual-feed plating carrier feeds Lycra simultaneously, positioning it on the fabric back.');
INSERT INTO fabric_patterns (fabric_id,pattern_name,courses_per_repeat,wales_per_repeat,pattern_type,pattern_cylinder,pattern_dial,cam_arrangement,needle_butt_pattern,needle_description) VALUES (15,'default',2,2,'double','[["K"],["K"]]','[["K"],["T"]]','[{"feed":1,"cylinder":"K","dial":"K","note":"Course 1: full rib (knit on both beds)"},{"feed":2,"cylinder":"K","dial":"T","note":"Course 2: cylinder knits, dial tucks"}]','C_D_C_D','1:1 alternating cylinder/dial. Dial needles tucked every second course.');
INSERT INTO fabric_patterns (fabric_id,pattern_name,courses_per_repeat,wales_per_repeat,pattern_type,pattern_cylinder,pattern_dial,cam_arrangement,needle_butt_pattern,needle_description) VALUES (16,'default',2,2,'double','[["K"],["T"]]','[["T"],["K"]]','[{"feed":1,"cylinder":"K","dial":"T","note":"Course 1: Cylinder knits, dial tucks"},{"feed":2,"cylinder":"T","dial":"K","note":"Course 2: Cylinder tucks, dial knits"}]','C_D_C_D','1:1 alternating. Both beds alternate between knitting and tucking each course.');
INSERT INTO fabric_patterns (fabric_id,pattern_name,courses_per_repeat,wales_per_repeat,pattern_type,pattern_cylinder,pattern_dial,cam_arrangement,needle_butt_pattern,needle_description) VALUES (17,'default',2,2,'double','[["K"],["K"]]','[["K"],["M"]]','[{"feed":1,"cylinder":"K","dial":"K","note":"Course 1: 1×1 rib course (both beds knit)"},{"feed":2,"cylinder":"K","dial":"M","note":"Course 2: cylinder only (dial disengaged / retracted)"}]','C_D_C_D','1:1 alternating; dial needles retracted on every second course.');
INSERT INTO fabric_patterns (fabric_id,pattern_name,courses_per_repeat,wales_per_repeat,pattern_type,pattern_cylinder,pattern_dial,cam_arrangement,needle_butt_pattern,needle_description) VALUES (18,'default',3,2,'double','[["K"],["K"],["M"]]','[["K"],["M"],["K"]]','[{"feed":1,"cylinder":"K","dial":"K","note":"Course 1: 1×1 rib (both beds)"},{"feed":2,"cylinder":"K","dial":"M","note":"Course 2: plain cylinder only"},{"feed":3,"cylinder":"M","dial":"K","note":"Course 3: plain dial only"}]','C_D_C_D','1:1 alternating. Cylinder and dial alternately retracted in courses 2 and 3.');
INSERT INTO fabric_patterns (fabric_id,pattern_name,courses_per_repeat,wales_per_repeat,pattern_type,pattern_cylinder,pattern_dial,cam_arrangement,needle_butt_pattern,needle_description) VALUES (19,'default',1,4,'double','[["K","K","K","M"]]','[["K","K","K","K"]]','[{"feed":1,"cylinder":"K on active needles","dial":"K","note":"Active needles knit; missing needle positions form vertical channel/ladder"}]','CCC_','3 active cylinder needles then 1 removed needle slot. Pattern repeats. Dial: standard.');
INSERT INTO fabric_patterns (fabric_id,pattern_name,courses_per_repeat,wales_per_repeat,pattern_type,pattern_cylinder,pattern_dial,cam_arrangement,needle_butt_pattern,needle_description) VALUES (20,'default',2,2,'double','[["K","M"],["M","K"]]','[["M","K"],["K","M"]]','[{"feed":1,"cylinder":"K on A needles, M on B","dial":"M on A, K on B","note":"Feed 1: odd-position knit on cyl, even on dial"},{"feed":2,"cylinder":"M on A, K on B","dial":"K on A, M on B","note":"Feed 2: opposite — even-position knit on cyl, odd on dial"}]','A_B_A_B (cylinder) offset to B_A_B_A (dial)','Long (A) and short (B) butt alternating on cylinder. Dial: inverse pattern. Each feed activates complementary set.');
INSERT INTO fabric_patterns (fabric_id,pattern_name,courses_per_repeat,wales_per_repeat,pattern_type,pattern_cylinder,pattern_dial,cam_arrangement,needle_butt_pattern,needle_description) VALUES (21,'default',4,2,'double','[["K","M"],["M","K"],["K","K"],["M","M"]]','[["M","K"],["K","M"],["M","M"],["K","K"]]','[{"feed":1,"cylinder":"K/M alternate","dial":"M/K alternate","note":"Course 1: Interlock feed A"},{"feed":2,"cylinder":"M/K alternate","dial":"K/M alternate","note":"Course 2: Interlock feed B"},{"feed":3,"cylinder":"K all","dial":"M all","note":"Course 3: Plain cylinder course (dial retracted)"},{"feed":4,"cylinder":"M all","dial":"K all","note":"Course 4: Plain dial course (cylinder retracted)"}]','A_B (cyl) / B_A (dial) — as interlock','Standard interlock gating. Courses 3&4 use full-width cam engagement on one bed at a time.');
INSERT INTO fabric_patterns (fabric_id,pattern_name,courses_per_repeat,wales_per_repeat,pattern_type,pattern_cylinder,pattern_dial,cam_arrangement,needle_butt_pattern,needle_description) VALUES (22,'default',2,4,'double','[["K","K","M","M"],["M","M","K","K"]]','[["M","M","K","K"],["K","K","M","M"]]','[{"feed":1,"cylinder":"K on AABB pattern","dial":"K on BBAA","note":"Groups of 2 active on alternate positions"},{"feed":2,"cylinder":"K on BBAA","dial":"K on AABB","note":"Interlocking complement"}]','AABB_AABB (cyl) / BBAA_BBAA (dial)','Groups of 2 long-butt then 2 short-butt needles alternating. Creates a 2×2 interlock effect.');
INSERT INTO fabric_patterns (fabric_id,pattern_name,courses_per_repeat,wales_per_repeat,pattern_type,pattern_cylinder,pattern_dial,cam_arrangement,needle_butt_pattern,needle_description) VALUES (23,'default',5,2,'double','[["K"],["K"],["K"],["K"],["K","M"]]','[["M"],["M"],["M"],["M"],["M","K"]]','[{"feed":"1-4","cylinder":"K all","dial":"M (held)","note":"Courses 1-4: Only cylinder knits; dial loops held (accumulate)"},{"feed":5,"cylinder":"K/M alternate","dial":"M/K alternate","note":"Course 5: Interlock to anchor held dial loops — creates cord"}]','Standard interlock','Standard interlock gating. Dial needles held (not activated) for several courses, creating trapped float which forms cord.');
INSERT INTO fabric_patterns (fabric_id,pattern_name,courses_per_repeat,wales_per_repeat,pattern_type,pattern_cylinder,pattern_dial,cam_arrangement,needle_butt_pattern,needle_description) VALUES (24,'default',4,4,'double','[["K","K","K","K"],["K","M","K","M"],["K","K","K","K"],["K","M","K","M"]]','[["K","K","K","K"],["M","K","M","K"],["K","K","K","K"],["M","K","M","K"]]','[{"feed":1,"cylinder":"K all","dial":"K all","note":"Course 1: full rib"},{"feed":2,"cylinder":"K/M alternate","dial":"M/K alternate","note":"Course 2: miss on alternate"},{"feed":3,"cylinder":"K all","dial":"K all","note":"Course 3: full rib"},{"feed":4,"cylinder":"K/M alternate (offset)","dial":"M/K alternate (offset)","note":"Course 4: miss at offset wales"}]','Standard interlock ABAB','Interlock gating with selective engagement via cam settings for miss courses.');
